insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 8, 'Find the sum of interior angles of a 5-sided polygon.', '5-sided polygon के interior angles का sum ज्ञात कीजिए।', 'Interior angle sum = (n-2)×180 = (5-2)×180 = 540°. Therefore, answer = 540°.', 'Joining one vertex to non-adjacent vertices partitions an n-sided polygon into n-2 triangles. Each triangle contributes 180 degrees. Final answer is 540°.', 'Interior angle sum = (n-2)×180 = (5-2)×180 = 540°। अतः answer = 540°।', 'एक vertex से diagonals खींचने पर n-sided polygon n-2 triangles में बँटता है। हर triangle 180° देता है। Final answer 540° है।', 'MEDIUM', array['geometry','polygons']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
